mapper.insert:
        INSERT  /* @SQLID=SUB0511_02-02#Sql003 */
        INTO CORDYS.SUG_BOX_COMMON (
		    SBC_NO
		    , TITLE
		    , CATEGORY
		    , STATUS
		    , SUGGESTION
		    , FILE1
		    , FILE2
		    , FILE3
		    , CREATE_TIME
		    , CREATE_USER
		    , UPDATE_TIME
		    , UPDATE_USER
		)
		VALUES(
			TO_NUMBER(#{req.sbcNo})
			, #{req.title}
			, #{req.category}
			, #{req.status}
			, #{req.suggestion}
			, #{req.registerFileName1}
			, #{req.registerFileName2}
			, #{req.registerFileName3}
			, IFA_DATE_UTIL.IFA_GET_DATE
			, #{req.userId}
			, IFA_DATE_UTIL.IFA_GET_DATE
			, #{req.userId}
		)

        INSERT /* @SQLID=SUB0511_02-02#Sql004 */
        INTO CORDYS.SUG_BOX_COMMON_A (
		    SBC_NO
		    , SBCA_NO
		    , ANSWER_DATE
		    , ANSWER_UPDATE_DATE
		    , ANSWER
		    , CREATE_TIME
		    , CREATE_USER
		    , UPDATE_TIME
		    , UPDATE_USER
		) 
		VALUES ( 
            TO_NUMBER(#{req.sbcNo})
            , TO_NUMBER(#{req.answerNo})
            , #{req.answerRegisterDate}
            , #{req.answerRegisterDate}
            , #{req.answerContents}
            , IFA_DATE_UTIL.IFA_GET_DATE
            , #{req.userId}
            , IFA_DATE_UTIL.IFA_GET_DATE
            , #{req.userId}
        )
